query:
-- Count all Telstra mobile services and their status
SELECT status, COUNT(*) as count, SUM(monthlyCost) as totalCost
FROM services
WHERE provider = 'Telstra' AND serviceType = 'Mobile'
GROUP BY status;

-- Check how many have BLITZ prefix (from previous Blitz termination review)
SELECT COUNT(*) as blitzCount FROM services WHERE externalId LIKE 'BLITZ-%' AND provider = 'Telstra';

-- Check how many are already linked to Smile IT (C2441)
SELECT COUNT(*) as smileItLinked FROM services WHERE customerExternalId = 'C2441' AND provider = 'Telstra';

-- Check the supplierAccount for existing Telstra mobile services
SELECT DISTINCT supplierAccount FROM services WHERE provider = 'Telstra' AND serviceType = 'Mobile' LIMIT 10;

